// First, find the Mangpa River (Lancang) and countries it flows through
MATCH (mangpa:River {name: 'Mangpa River'})-[:flowsThrough]-(c:Country)
WITH collect(c) AS flowedThroughCountries
// Find countries in the Yellow River Basin (assuming Yellow River Basin is a DrainageBasin)
MATCH (yellowRiverBasin:DrainageBasin)<-[:locatedIn]-(countryInBasin:Country)
WITH flowedThroughCountries, collect(DISTINCT countryInBasin) AS basinCountries
// Combine and count unique countries
WITH flowedThroughCountries + basinCountries AS allCountries
RETURN size(allCountries) AS totalCountries

MATCH (c:Country)
WHERE EXISTS {
  MATCH (c)-[:locatedIn]->(cont:Continent {name: 'Asia'})
} OR EXISTS {
  MATCH (r:River {name: 'Karabolka'})-[:flowsThrough]->(c)
}
RETURN count(DISTINCT c)
